import path from 'node:path';
import { logMemoryUsage, withMemoryLogging } from '../shared/memoryUtils.js';
import { collectFiles } from './file/fileCollect.js';
import { sortPaths } from './file/filePathSort.js';
import { processFiles } from './file/fileProcess.js';
import { searchFiles } from './file/fileSearch.js';
import { getGitDiffs } from './git/gitDiffHandle.js';
import { getGitLogs } from './git/gitLogHandle.js';
import { calculateMetrics } from './metrics/calculateMetrics.js';
import { produceOutput } from './packager/produceOutput.js';
import { validateFileSafety } from './security/validateFileSafety.js';
import { packSkill } from './skill/packSkill.js';
const defaultDeps = {
    searchFiles,
    collectFiles,
    processFiles,
    validateFileSafety,
    produceOutput,
    calculateMetrics,
    sortPaths,
    getGitDiffs,
    getGitLogs,
    packSkill,
};
export const pack = async (rootDirs, config, progressCallback = () => { }, overrideDeps = {}, explicitFiles, options = {}) => {
    const deps = {
        ...defaultDeps,
        ...overrideDeps,
    };
    logMemoryUsage('Pack - Start');
    progressCallback('Searching for files...');
    const filePathsByDir = await withMemoryLogging('Search Files', async () => Promise.all(rootDirs.map(async (rootDir) => ({
        rootDir,
        filePaths: (await deps.searchFiles(rootDir, config, explicitFiles)).filePaths,
    }))));
    progressCallback('Sorting files...');
    const allFilePaths = filePathsByDir.flatMap(({ filePaths }) => filePaths);
    const sortedFilePaths = deps.sortPaths(allFilePaths);
    const sortedFilePathsByDir = rootDirs.map((rootDir) => ({
        rootDir,
        filePaths: sortedFilePaths.filter((filePath) => filePathsByDir.find((item) => item.rootDir === rootDir)?.filePaths.includes(filePath)),
    }));
    progressCallback('Collecting files...');
    const collectResults = await withMemoryLogging('Collect Files', async () => await Promise.all(sortedFilePathsByDir.map(({ rootDir, filePaths }) => deps.collectFiles(filePaths, rootDir, config, progressCallback))));
    const rawFiles = collectResults.flatMap((curr) => curr.rawFiles);
    const allSkippedFiles = collectResults.flatMap((curr) => curr.skippedFiles);
    progressCallback('Getting git diffs...');
    const gitDiffResult = await deps.getGitDiffs(rootDirs, config);
    progressCallback('Getting git logs...');
    const gitLogResult = await deps.getGitLogs(rootDirs, config);
    const { safeFilePaths, safeRawFiles, suspiciousFilesResults, suspiciousGitDiffResults, suspiciousGitLogResults } = await withMemoryLogging('Security Check', () => deps.validateFileSafety(rawFiles, progressCallback, config, gitDiffResult, gitLogResult));
    progressCallback('Processing files...');
    const processedFiles = await withMemoryLogging('Process Files', () => deps.processFiles(safeRawFiles, config, progressCallback));
    progressCallback('Generating output...');
    if (config.skillGenerate !== undefined && options.skillDir) {
        const result = await deps.packSkill({
            rootDirs,
            config,
            options,
            processedFiles,
            allFilePaths,
            gitDiffResult,
            gitLogResult,
            suspiciousFilesResults,
            suspiciousGitDiffResults,
            suspiciousGitLogResults,
            safeFilePaths,
            skippedFiles: allSkippedFiles,
            progressCallback,
        });
        logMemoryUsage('Pack - End');
        return result;
    }
    const filePathsByRoot = sortedFilePathsByDir.map(({ rootDir, filePaths }) => ({
        rootLabel: path.basename(rootDir) || rootDir,
        files: filePaths,
    }));
    const { outputFiles, outputForMetrics } = await deps.produceOutput(rootDirs, config, processedFiles, allFilePaths, gitDiffResult, gitLogResult, progressCallback, filePathsByRoot);
    const metrics = await withMemoryLogging('Calculate Metrics', () => deps.calculateMetrics(processedFiles, outputForMetrics, progressCallback, config, gitDiffResult, gitLogResult));
    const result = {
        ...metrics,
        ...(outputFiles && { outputFiles }),
        suspiciousFilesResults,
        suspiciousGitDiffResults,
        suspiciousGitLogResults,
        processedFiles,
        safeFilePaths,
        skippedFiles: allSkippedFiles,
    };
    logMemoryUsage('Pack - End');
    return result;
};
